import React, { useState, useEffect } from "react";
import "./App.css";

/* ---------- data ---------- */
const pieces = [
  {
    src: "/artwork/cat1.jpg",
    title: "Shy Gatito",
    medium: "Procreate / Digital Art",
    date: "01/10/2025",
    category: "Digital",
  },
  {
    src: "/artwork/cat2.jpg",
    title: "Sunshine Gatito",
    medium: "Procreate / Digital Art",
    date: "02/11/2025",
    category: "Digital",
  },
  {
    src: "/artwork/buba1.jpg",
    title: "Buba",
    medium: "Procreate / Digital Art",
    date: "03/14/2025",
    category: "Digital",
  },
];

const categories = ["All", "Digital", "Pencil", "Colored Pencil"];

/* ---------- slideshow ---------- */
function Slideshow({ images, interval = 5000 }) {
  const [index, setIndex] = useState(0);

  useEffect(() => {
    const id = setInterval(
      () => setIndex((i) => (i + 1) % images.length),
      interval
    );
    return () => clearInterval(id);
  }, [images.length, interval]);

  return (
    <div className="slideshow">
      {images.map((img, i) => (
        <div
          key={img.src}
          className={`slideshow__slide ${i === index ? "is-active" : ""}`}
          style={{ backgroundImage: `url(${img.src})` }}
        />
      ))}
    </div>
  );
}

/* ---------- navigation link ---------- */
function NavLink({ label, active, onClick }) {
  return (
    <button
      type="button"
      className={`nav__link ${active ? "is-active" : ""}`}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

/* ---------- category button ---------- */
function CategoryButton({ label, active, onClick }) {
  return (
    <button
      type="button"
      className={`filter__btn ${active ? "is-active" : ""}`}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

/* ---------- card ---------- */
function Card({ piece }) {
  return (
    <article className="card">
      <img
        src={piece.src}
        alt={piece.title}
        className="card__img is-loaded"
        loading="lazy"
      />
      <div className="card__body">
        <h3 className="card__title">{piece.title}</h3>
        <p className="card__meta">{piece.medium}</p>
        <span className="card__date">{piece.date}</span>
      </div>
    </article>
  );
}

/* ---------- main ---------- */
export default function App() {
  const [view, setView] = useState("home"); // home | gallery | about
  const [category, setCategory] = useState("All");

  const filtered =
    category === "All"
      ? pieces
      : pieces.filter((p) => p.category === category);

  return (
    <>
      <header className="site-header">
        <div className="copyright">&copy; 2025 Emely Recinos</div>
        <nav className="nav">
          {["Home", "Gallery", "About"].map((label) => (
            <NavLink
              key={label}
              label={label}
              active={view === label.toLowerCase()}
              onClick={() => setView(label.toLowerCase())}
            />
          ))}
        </nav>
      </header>

      {view === "home" && (
        <section className="home">
          <Slideshow images={pieces} />

          <div className="home-intro">
            <h1 className="home-title">Emely Recinos</h1>
            <p className="home-bio">
              Digital artist exploring character, color, and texture. Aspiring
              tattoo professional sharing work in progress.
            </p>
            <button
              className="nav__link is-active"
              onClick={() => setView("gallery")}
              aria-label="Open gallery"
            >
              {/* long right arrow */}
              <svg
                width="56"
                height="16"
                viewBox="0 0 56 16"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
              >
                <path
                  d="M0 8H54"
                  stroke="currentColor"
                  strokeWidth="2"
                  strokeLinecap="round"
                />
                <path
                  d="M48 2L54 8L48 14"
                  stroke="currentColor"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </button>
          </div>
        </section>
      )}

      {view === "gallery" && (
        <main className="gallery fade">
          <div className="divider" />
          <div className="filter-wrap">
            <div className="filter">
              {categories.map((c) => (
                <CategoryButton
                  key={c}
                  label={c}
                  active={category === c}
                  onClick={() => setCategory(c)}
                />
              ))}
            </div>
            <span className="filter-fade" />
          </div>

          <div className="grid">
            {filtered.map((p) => (
              <Card key={p.src} piece={p} />
            ))}
          </div>
        </main>
      )}

      {view === "about" && (
        <section className="about fade">
          <div className="divider" />
          <p>
            I'm Emely, a digital illustrator training to become a tattoo artist.
            This site is my gallery and contact hub. Thanks for stopping by!
          </p>
        </section>
      )}

      <footer className="site-footer">
        <div className="divider" />
        <p className="footer-text">
          &copy; 2025 Emely Recinos. All rights reserved.
        </p>
      </footer>
    </>
  );
}
